import { useEffect, useState } from "react";
import axios from "axios";
import AnimatedLetters from "../AnimatedLetters";
import "./index.scss";

const Predictions = () => {
  const [rows, setRows] = useState([]);
  const [error, setError] = useState("");
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    axios
      .get("http://localhost:8080/api/v1/predictions")
      .then((response) => {
        setRows(response.data || []);
        setLoading(false);
      })
      .catch((e) => {
        setError(e.message);
        setLoading(false);
      });
  }, []);

  return (
    <div className="container predictions-page">
      <h1 className="page-title">
        <AnimatedLetters letterClass="text-animate" strArray={"Predictions".split("")} idx={12} />
      </h1>

      {loading && <p>Loading predictions...</p>}
      {error && <p>Error: {error}</p>}

      {!loading && !error && (
        <>
          <div className="prediction-summary">
            <div className="pill">Fixtures: {rows.length}</div>
            <div className="pill">Home Wins: {rows.filter((r) => r.prediction === "Home Win").length}</div>
            <div className="pill">Away Wins: {rows.filter((r) => r.prediction === "Away Win").length}</div>
            <div className="pill">Draws: {rows.filter((r) => r.prediction === "Draw").length}</div>
          </div>

          {rows.length === 0 ? (
            <p className="empty-state">No prediction rows found yet. Run the predictor script and refresh.</p>
          ) : (
            <div className="predictions-table-wrap">
              <table>
                <thead>
                  <tr>
                    <th>Date</th>
                    <th>Time</th>
                    <th>Home</th>
                    <th>Away</th>
                    <th>Home Win Prob</th>
                    <th>Away Win Prob</th>
                    <th>Prediction</th>
                  </tr>
                </thead>
                <tbody>
                  {rows.map((r, idx) => (
                    <tr key={`${r.date}-${r.time}-${r.home_team}-${idx}`}>
                      <td>{r.date}</td>
                      <td>{r.time}</td>
                      <td>{r.home_team}</td>
                      <td>{r.away_team}</td>
                      <td>{r.home_win_prob}</td>
                      <td>{r.away_win_prob}</td>
                      <td>{r.prediction}</td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          )}
        </>
      )}
    </div>
  );
};

export default Predictions;
